async function isVaultStale(userId) {
  try {
    const pages = await db.select({ slug: knowledgeVaultPages.slug, generatedAt: knowledgeVaultPages.generatedAt }).from(knowledgeVaultPages).where(
      and15(
        eq19(knowledgeVaultPages.userId, userId),
        isNull(knowledgeVaultPages.archivedAt)
      )
    );
    const presentSlugs = new Set(pages.map((p) => p.slug));
    const allPresent = VAULT_SLUGS.every((s) => presentSlugs.has(s));
    if (!allPresent) return true;
    const oldestGeneratedAt = pages.reduce(
      (oldest, p) => p.generatedAt < oldest ? p.generatedAt : oldest,
      pages[0].generatedAt
    );
    const ageMs = Date.now() - oldestGeneratedAt.getTime();
    if (ageMs > VAULT_TTL_MS) return true;
    const newMemories = await db.select({ count: count() }).from(userMemories).where(
      and15(
        eq19(userMemories.userId, userId),
        gte3(userMemories.extractedAt, oldestGeneratedAt)
      )
    );
    return (newMemories[0]?.count ?? 0) >= VAULT_NOVELTY_THRESHOLD;
  } catch (err2) {
    console.error("[Vault] isVaultStale check failed:", err2);
    return true;
  }
}
