    browserScreenshotTool = {
      name: "browser_screenshot",
      description: "Capture a screenshot of the current browser page and return it as a base64-encoded PNG image. Use this to visually inspect the current page state or read content that isn't accessible as text.\n\nCRITICAL \u2014 only describe what you can actually see: After capturing, you MUST describe only content that is visibly present in the screenshot. If the page shows a login prompt, header only, error page, or anything other than the content you were asked to capture, state clearly what IS visible and stop. NEVER describe, invent, summarise, or guess at content that is not directly visible in the image. Fabricating post content, article text, or any other information you cannot see is a critical accuracy violation.",
      parameters: {
        type: "object",
        properties: {
          full_page: { type: "boolean", description: "Capture the full scrollable page (default: false = viewport only)" }
        }
      },
      async execute(args, ctx) {
        if (!await hasActiveBrowserContext(ctx.userId)) {
          return { ok: false, content: "No active browser session. Call browser_navigate first.", label: "browser_screenshot: no session" };
        }
        try {
          const fullPage = Boolean(args.full_page);
          const result = await callBrowserTool(ctx.userId, "browser_take_screenshot", { type: "png", fullPage });
          if (result.isError) {
            return { ok: false, content: `browser_screenshot failed: ${mcpText(result.content)}`, label: "browser_screenshot: error" };
          }
          const inline = result.content.find((c) => c.type === "image" && c.data);
          let base64 = inline?.data ?? null;
          if (!base64) base64 = popLatestScreenshot(ctx.userId);
          if (!base64) {
            return { ok: false, content: "Screenshot taken but image data unavailable.", label: "browser_screenshot: no data" };
          }
          let loginHint = "";
          let contentVisible = true;
          let wallType = "none";
          let detectedPlatform;
          try {
            const snapResult = await callBrowserTool(ctx.userId, "browser_snapshot", {});
            if (!snapResult.isError) {
              const pageText = mcpText(snapResult.content);
              const currentUrl = extractFinalUrl(pageText) ?? "";
              const socialPlatform = isSocialAuthGate(currentUrl, pageText, null);
              const looksLikeLoginPage = pageText.toLowerCase().includes("log in") && pageText.length < 5e3;
              if (socialPlatform) {
                contentVisible = false;
                wallType = "social_login";
                detectedPlatform = socialPlatform;
                loginHint = `

\u26A0\uFE0F NOTE: This page appears to be a ${socialPlatform} login wall. The target content may not be visible. Describe ONLY what you can see in the image.`;
              } else if (looksLikeLoginPage) {
                contentVisible = false;
                wallType = "login_or_access";
                loginHint = `

\u26A0\uFE0F NOTE: This page appears to be a login or access wall. The target content may not be visible. Describe ONLY what you can see in the image.`;
              }
            }
          } catch {
          }
          console.log(`[${ctx.channel || "Agent"}] browser_screenshot full=${fullPage} encoded_size=${base64.length} contentVisible=${contentVisible}`);
          if (ctx?.projectId) incrementAppProjectScreenshotCount(ctx.projectId);
          return {
            ok: true,
            content: `Screenshot captured.

[image/png;base64,${base64}]${loginHint}`,
            label: "Screenshot captured",
            detail: `${Math.round(base64.length * 3 / 4)} bytes`,
            metadata: {
              contentVisible,
              wallType,
              ...detectedPlatform ? { platform: detectedPlatform } : {}
            }
          };
        } catch (err2) {
          const msg = err2 instanceof Error ? err2.message.split("\n")[0] : String(err2);
          return { ok: false, content: `browser_screenshot failed: ${msg}`, label: "browser_screenshot: error" };
        }
      }
    };
