function registerVoiceRelay(server) {
  const wss = new WebSocketServer3({ noServer: true });
  server.on("upgrade", (req, socket, head) => {
    const url = new URL(req.url || "", "http://localhost");
    if (!url.pathname.startsWith("/api/voice/ws")) return;
    const ticket = url.searchParams.get("ticket") || "";
    const userId = consumeTicket(ticket);
    if (!userId) {
      socket.write("HTTP/1.1 401 Unauthorized\r\nContent-Length: 0\r\n\r\n");
      socket.destroy();
      return;
    }
    wss.handleUpgrade(req, socket, head, (clientWs) => {
      wss.emit("connection", clientWs, req, userId);
    });
  });
  wss.on("connection", async (clientWs, _req, userId) => {
    console.log(`[voice-relay] client connected userId=${userId}`);
    const openaiKey = process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
    if (!openaiKey) {
      console.error("[voice-relay] No OpenAI API key \u2014 closing connection");
      clientWs.close(1011, "Server misconfiguration: missing API key");
      return;
    }
    const model = "gpt-4o-realtime-preview-2024-12-17";
    const openaiWs = new WebSocket3(
      `wss://api.openai.com/v1/realtime?model=${model}`,
      {
        headers: {
          Authorization: `Bearer ${openaiKey}`,
          "OpenAI-Beta": "realtime=v1"
        }
      }
    );
    const clientMessageQueue = [];
    let sessionReady = false;
    const flushQueue = () => {
      sessionReady = true;
      for (const msg of clientMessageQueue) {
        if (openaiWs.readyState === WebSocket3.OPEN) {
          try {
            openaiWs.send(msg);
          } catch {
          }
        }
      }
      clientMessageQueue.length = 0;
    };
    openaiWs.on("open", async () => {
      console.log(`[voice-relay] OpenAI connection open for userId=${userId}`);
      try {
        const instructions = await buildJarvisInstructions(userId);
        const sessionUpdate = {
          type: "session.update",
          session: {
            instructions,
            voice: "verse",
            modalities: ["text", "audio"],
            input_audio_format: "pcm16",
            output_audio_format: "pcm16",
            input_audio_transcription: { model: "whisper-1" },
            turn_detection: {
              type: "server_vad",
              threshold: 0.5,
              prefix_padding_ms: 300,
              silence_duration_ms: 500
            },
            tools: [
              {
                type: "function",
                name: "get_today_summary",
                description: "Get the user's tasks and upcoming scheduled items for today",
                parameters: { type: "object", properties: {} }
              },
              {
                type: "function",
                name: "search_memories",
                description: "Search the user's personal memories and knowledge base",
                parameters: {
                  type: "object",
                  properties: {
                    query: { type: "string", description: "The search query" }
                  },
                  required: ["query"]
                }
              }
            ],
            tool_choice: "auto"
          }
        };
        openaiWs.send(JSON.stringify(sessionUpdate));
        console.log(`[voice-relay] session.update sent for userId=${userId}`);
        flushQueue();
      } catch (err2) {
        console.error("[voice-relay] Failed to configure session:", err2);
        flushQueue();
      }
    });
    openaiWs.on("message", (data) => {
      if (clientWs.readyState === WebSocket3.OPEN) {
        try {
          clientWs.send(data.toString());
        } catch (err2) {
          console.error("[voice-relay] Failed to forward OpenAI\u2192client:", err2);
        }
      }
    });
    openaiWs.on("error", (err2) => {
      console.error("[voice-relay] OpenAI WebSocket error:", err2);
      if (clientWs.readyState === WebSocket3.OPEN) {
        clientWs.close(1011, "OpenAI connection error");
      }
    });
    openaiWs.on("close", (code, reason) => {
      console.log(`[voice-relay] OpenAI WS closed code=${code} reason=${reason?.toString()}`);
      if (clientWs.readyState === WebSocket3.OPEN) {
        clientWs.close(code || 1e3, reason?.toString() || "");
      }
    });
    clientWs.on("message", (data) => {
      if (!sessionReady) {
        if (clientMessageQueue.length < 50) {
          clientMessageQueue.push(data.toString());
        }
        return;
      }
      if (openaiWs.readyState === WebSocket3.OPEN) {
        try {
          openaiWs.send(data.toString());
        } catch (err2) {
          console.error("[voice-relay] Failed to forward client\u2192OpenAI:", err2);
        }
      }
    });
    clientWs.on("close", (code, reason) => {
      console.log(`[voice-relay] client WS closed code=${code} userId=${userId}`);
      if (openaiWs.readyState === WebSocket3.OPEN || openaiWs.readyState === WebSocket3.CONNECTING) {
        openaiWs.close(1e3, reason?.toString() || "");
      }
    });
    clientWs.on("error", (err2) => {
      console.error("[voice-relay] Client WebSocket error:", err2);
      if (openaiWs.readyState === WebSocket3.OPEN) {
        openaiWs.close(1e3, "");
      }
    });
    const keepalive = setInterval(() => {
      if (openaiWs.readyState === WebSocket3.OPEN) {
        try {
          openaiWs.ping();
        } catch {
        }
      } else {
        clearInterval(keepalive);
      }
    }, 2e4);
    clientWs.on("close", () => clearInterval(keepalive));
  });
  console.log("[voice-relay] WebSocket relay mounted at /api/voice/ws");
}

