var KNOWN_WS_PATHS = ["/api/daemon/ws", "/api/voice/ws", "/api/gateway/ws"];
function registerRealtimeBoot(app2, server) {
  initChannels();
  startDaemonBridge(server);
  registerGatewayControlPlane(app2, server);
  registerVoiceRelay(server);
  server.on("upgrade", (req, socket) => {
    const pathname = (req.url || "").split("?")[0];
    const isKnown = KNOWN_WS_PATHS.some((p) => pathname.startsWith(p));
    if (!isKnown && !socket.destroyed) {
      socket.write("HTTP/1.1 404 Not Found\r\nContent-Length: 0\r\n\r\n");
      socket.destroy();
    }
  });
}

